27	/***********************************************************************
28	 * Helper Functions
29	 **********************************************************************/
30	/*!
31	 * Make a device hash that maps 1 to 1 with a device address.
32	 * The hash will be used to identify created devices.
33	 * \param dev_addr the device address
34	 * \return the hash number
35	 */
36	static size_t hash_device_addr(const device_addr_t& dev_addr)
37	{
38	    // combine the hashes of sorted keys/value pairs
39	    size_t hash = 0;
40	
41	    // The device addr can contain all sorts of stuff, which sometimes gets in
42	    // the way of hashing reliably. TODO: Make this a whitelist
43	    const std::vector<std::string> hash_key_blacklist = {
44	        "claimed", "skip_dram", "skip_ddc", "skip_duc"};
45	
46	    if (dev_addr.has_key("resource")) {
47	        boost::hash_combine(hash, "resource");
48	        boost::hash_combine(hash, dev_addr["resource"]);
49	    } else {
50	        for (const std::string& key : uhd::sorted(dev_addr.keys())) {
51	            if (std::find(hash_key_blacklist.begin(), hash_key_blacklist.end(), key)
52	                == hash_key_blacklist.end()) {
53	                boost::hash_combine(hash, key);
54	                boost::hash_combine(hash, dev_addr[key]);
55	            }
56	        }
57	    }
58	    return hash;
59	}
