67	UHD_SINGLETON_FCN(std::vector<dev_fcn_reg_t>, get_dev_fcn_regs)
68	
69	void device::register_device(
70	    const find_t& find, const make_t& make, const device_filter_t filter)
71	{
72	    // UHD_LOGGER_TRACE("UHD") << "registering device";
73	    get_dev_fcn_regs().push_back(dev_fcn_reg_t(find, make, filter));
74	}
