81	/***********************************************************************
82	 * Discover
83	 **********************************************************************/
84	
85	// Internal function that discovers devices and returns them with their make functions
86	static std::vector<std::tuple<device_addr_t, device::make_t>>
87	discover_devices_with_makers(const device_addr_t& hint, device::device_filter_t filter)
88	{
89	    std::vector<std::tuple<device_addr_t, device::make_t>> device_maker_pairs;
90	
91	    // Launch async find tasks with their corresponding make functions
92	    std::vector<std::pair<std::future<device_addrs_t>, device::make_t>> tasks;
93	    for (const auto& fcn : get_dev_fcn_regs()) {
94	        if (filter == device::ANY or std::get<2>(fcn) == filter) {
95	            tasks.emplace_back(std::async(std::launch::async,
96	                                   [fcn, hint]() { return std::get<0>(fcn)(hint); }),
97	                std::get<1>(fcn));
98	        }
99	    }
100	
101	    // Collect results from async tasks
102	    for (auto& [task, maker] : tasks) {
103	        try {
104	            device_addrs_t discovered_addrs = task.get();
105	            for (const auto& addr : discovered_addrs) {
106	                device_maker_pairs.emplace_back(addr, maker);
107	            }
108	        } catch (const std::exception& e) {
109	            UHD_LOGGER_ERROR("UHD") << "Device discovery error: " << e.what();
110	        }
111	    }
112	
113	    return device_maker_pairs;
114	}
115	
116	// Internal function that returns filtered device-maker pairs
117	static std::vector<std::tuple<device_addr_t, device::make_t>>
118	find_filtered_devices_with_makers(
119	    const device_addr_t& hint, device::device_filter_t filter)
120	{
121	    // Get devices with their makers
122	    auto device_maker_pairs = discover_devices_with_makers(hint, filter);
123	
124	    std::vector<std::tuple<device_addr_t, device::make_t>> filtered_pairs;
125	
126	    // Filter the discovered devices
127	    for (const auto& pair : device_maker_pairs) {
128	        const device_addr_t& discovered_addr = std::get<0>(pair);
129	
130	        // Filter with the optional keys name/serial/type/product
